const { MongoClient } = require('mongodb');

const MONGO_URL = 'mongodb://app:app@mongodb:27017/fraud?authSource=admin';

const items = $input.all();

if (items.length === 0) return [];

const virtualDocs = items.map((it) => {
  const p = it.json.payload;
  return {
    msg_id: it.json.msg_id,
    request_id: it.json.request_id,
    enqueued_at: it.json.enqueued_at,
    driver_id: p.driver_id,
    trip_id: p.trip_id,
    payload: p,
  };
});

const mongo = new MongoClient(MONGO_URL, { serverSelectionTimeoutMS: 5000 });

try {
  await mongo.connect();
  const db = mongo.db('fraud');

  const enriched = await db.aggregate([
    { $documents: virtualDocs },

    {
      $lookup: {
        from: 'drivers',
        localField: 'driver_id',
        foreignField: 'driver_id',
        as: '_driver',
      },
    },
    { $unwind: { path: '$_driver', preserveNullAndEmptyArrays: true } },

    {
      $lookup: {
        from: 'trips',
        localField: 'trip_id',
        foreignField: 'trip_id',
        as: '_trip',
      },
    },
    { $unwind: { path: '$_trip', preserveNullAndEmptyArrays: true } },

    {
      $lookup: {
        from: 'decisions',
        let: { drvId: '$driver_id' },
        pipeline: [
          { $match: { $expr: { $eq: ['$driver_id', '$$drvId'] } } },
          { $sort: { decided_at: -1 } },
          { $limit: 5 },
          { $project: { _id: 0, verdict: 1, source: 1, risk_score: 1, decided_at: 1 } },
        ],
        as: '_recent_decisions',
      },
    },

    {
      $lookup: {
        from: 'trips',
        let: { drvId: '$driver_id' },
        pipeline: [
          { $match: { $expr: { $eq: ['$driver_id', '$$drvId'] } } },
          { $sort: { completed_at: -1 } },
          { $limit: 5 },
          { $project: { _id: 0, trip_id: 1, fare_amount: 1, payment_status: 1, completed_at: 1 } },
        ],
        as: '_recent_trips',
      },
    },

    {
      $project: {
        _id: 0,
        msg_id: 1,
        request_id: 1,
        enqueued_at: 1,
        payload: 1,
        driver: '$_driver',
        trip: '$_trip',
        recent_decisions: '$_recent_decisions',
        recent_trips: '$_recent_trips',
      },
    },
  ]).toArray();

  const byRequestId = new Map(enriched.map((e) => [e.request_id, e]));

  return items.map((it) => {
    const e = byRequestId.get(it.json.request_id);
    return {
      json: e || {
        msg_id: it.json.msg_id,
        request_id: it.json.request_id,
        enqueued_at: it.json.enqueued_at,
        payload: it.json.payload,
        driver: null,
        trip: null,
        recent_decisions: [],
        recent_trips: [],
      },
    };
  });
} finally {
  await mongo.close();
}

const { MongoClient } = require('mongodb');

const MONGO_URL = 'mongodb://app:app@mongodb:27017/fraud?authSource=admin';
const mongo = new MongoClient(MONGO_URL, {
  serverSelectionTimeoutMS: 5000,
  maxPoolSize: 20,
});

try {
  await mongo.connect();
  const db = mongo.db('fraud');
  const decisionsCol = db.collection('decisions');
  const metricsCol = db.collection('metrics');

  const items = $input.all();
  if (items.length === 0) return [];

  const now = new Date();
  const decisionDocs = [];
  const metricDocs = [];

  for (const item of items) {
    const m = item.json;
    const decision = m.ai_decision ?? m.rule_decision;
    const source = decision?.source ?? 'unknown';
    const isAiFailure = source.startsWith('ai-') && source !== 'ai' && source !== 'ai-cache';
    const finalVerdict = decision?.verdict ?? (isAiFailure ? 'needs_review' : 'pending');

    const receivedAt = m.payload?.received_at ? new Date(m.payload.received_at) : null;
    const enqueuedAt = m.enqueued_at ? new Date(m.enqueued_at) : null;
    const dqMs = m._dequeued_at ? parseInt(m._dequeued_at, 10) : null;
    const dequeuedAt = (dqMs && !isNaN(dqMs)) ? new Date(dqMs) : null;

    const totalLatencyMs = receivedAt ? now.getTime() - receivedAt.getTime() : null;
    const queueWaitMs = (dequeuedAt && enqueuedAt) ? dequeuedAt.getTime() - enqueuedAt.getTime() : null;
    const serviceTimeMs = dequeuedAt ? now.getTime() - dequeuedAt.getTime() : null;

    decisionDocs.push({
      request_id: m.request_id,
      driver_id: m.payload?.driver_id,
      trip_id: m.payload?.trip_id,
      verdict: finalVerdict,
      risk_score: decision?.risk_score ?? null,
      source,
      reasoning: decision?.reasoning ?? '',
      key_factors: decision?.key_factors ?? [],
      decided_at: now,
      ai_model: m.ai_meta?.model ?? null,
      ai_tokens: m.ai_meta?.tokens ?? null,
      cb_state: m.ai_meta?.cb?.state ?? null,
      cb_trip_reason: m.ai_meta?.cb?.trip_reason ?? null,
    });

    metricDocs.push({
      request_id: m.request_id,
      timestamp: now,
      total_latency_ms: totalLatencyMs,
      queue_wait_ms: queueWaitMs,
      service_time_ms: serviceTimeMs,
      ai_called: source.startsWith('ai'),
      ai_success: source === 'ai',
      cache_hit: source === 'ai-cache',
      ai_unavailable: source === 'ai-unavailable',
      decision_source: source,
      decision_verdict: finalVerdict,
      risk_score: decision?.risk_score ?? null,
      cb_state: m.ai_meta?.cb?.state ?? null,
      cb_trip_reason: m.ai_meta?.cb?.trip_reason ?? null,
      cb_tripped: !!m.ai_meta?.cb?.trip_reason,
    });
  }

  const writtenIdx = new Set();
  try {
    await decisionsCol.insertMany(decisionDocs, { ordered: false });
    for (let i = 0; i < decisionDocs.length; i++) writtenIdx.add(i);
  } catch (err) {
    const writeErrors = err.writeErrors || (err.result?.result?.writeErrors) || [];
    const failedIdx = new Set(writeErrors.map((we) => we.index));
    for (let i = 0; i < decisionDocs.length; i++) {
      if (!failedIdx.has(i)) {
        writtenIdx.add(i);
      } else {
        const we = writeErrors.find((w) => w.index === i);
        if (we?.code === 11000) writtenIdx.add(i);
      }
    }
  }

  try {
    await metricsCol.insertMany(metricDocs, { ordered: false });
  } catch {}

  return items.map((item, i) => ({
    json: {
      ...item.json,
      _written: writtenIdx.has(i),
      _decision_source: decisionDocs[i].source,
    },
  }));
} finally {
  await mongo.close();
}

const Redis = require('ioredis');

const STREAM_KEY = 'fraud:stream:webhooks';
const GROUP_NAME = 'workers';

const redis = new Redis({
  host: 'redis',
  port: 6379,
  connectTimeout: 5000,
  commandTimeout: 5000,
  maxRetriesPerRequest: 2,
});

try {
  const items = $input.all();
  if (items.length === 0) return [];

  const pipeline = redis.pipeline();
  const acked = [];

  for (const item of items) {
    const m = item.json;
    if (m.msg_id) {
      pipeline.xack(STREAM_KEY, GROUP_NAME, m.msg_id);
      acked.push({ msg_id: m.msg_id, source: m._decision_source });
    }
  }

  if (acked.length > 0) {
    await pipeline.exec();
  }

  const groups = {};
  for (const a of acked) groups[a.source] = (groups[a.source] || 0) + 1;

  return [{
    json: {
      acked: acked.length,
      by_source: groups,
    },
  }];
} finally {
  await redis.quit();
}
